uniform int orient;
//the widget's current normalized value
uniform vec2 normValues;
uniform vec2 defaultValues;
uniform vec2 minMax;
uniform vec4 bgColor;
uniform vec4 indColor;
uniform vec4 knobColor;
uniform int knobSize;
//uniform float offset2;
//uniform float pOffset;
//uniform float scale;

layout(location = 0) out vec4 fragColor;

float map(float s, float a1, float a2, float b1, float b2)
{
    return b1 + (s-a1)*(b2-b1)/(a2-a1);
}

vec4 over(vec4 tOver, vec4 tUnder)
{
    return ((1.0-tOver.a)*tUnder) + tOver.a * tOver;
}

void main() {

    float normValue1 = normValues.x;
    float normValue2 = normValues.y;
    float defaultValue1 = defaultValues.x;
    float defaultValue2 = defaultValues.y;

    //level use v if orient is 1 else use u
    float level = orient == 1.0 ? vUV.t : vUV.s;
	//Flips the incoming text and textures to the correct orientation
	vec2 fUV = orient == 1.0 ? (vec2(0.0, 1.0)
								+ (vUV.ts*vec2(1.0, -1.0))) : vUV.st;
	float coord = orient == 1.0 ? gl_FragCoord.y : gl_FragCoord.x;
    float pWidth = uTD2DInfos[0].res.z;
	vec4 color = vec4(0.0);
	//ranged value
	float rmin = minMax.x;
	float rmax = minMax.y;
	//normalize knob size
	float nmKnobSize = knobSize / pWidth;
	float nmKnobSizeH = nmKnobSize/2.0;
	float nmDefault = (defaultValue1-rmin) / (rmax - rmin);
    float pOffset1 = -normValue1 * ((pWidth-(knobSize*2)) / knobSize);
    float pOffset2 = -normValue2 * ((pWidth-(knobSize*2)) / knobSize);
    float scale = pWidth / knobSize;
    //knob uv
    vec2 knobUV1 =  vec2(fUV.s*scale+pOffset1, fUV.t);
    vec2 knobUV2 =  vec2((fUV.s-nmKnobSize)*scale+pOffset2, fUV.t);
    //load textures
    //vec4 textLayer = texture(sTD2DInputs[0], fUV);
	vec4 bgLayer = texture(sTD2DInputs[1], fUV);
	vec4 knobLayer1 = texture(sTD2DInputs[0], knobUV1);
    vec4 knobLayer2 = texture(sTD2DInputs[0], knobUV2);

    float remapValue1 = map(normValue1, 0, 1, nmKnobSizeH,
                                        1-(nmKnobSizeH)-nmKnobSize);
    float remapValue2 = map(normValue2, 0, 1, nmKnobSizeH+nmKnobSize,
                                        1-(nmKnobSizeH));

	//Level indicator color
    if (level > (remapValue1+nmKnobSizeH) && level <
                                        (remapValue2-nmKnobSizeH))
    {
      color = indColor;
  	}
  	else
    {
  	   color = bgColor;
  	}

    //knob1 color
    if (level > (remapValue1 - (nmKnobSizeH)) &&
								level < (remapValue1 + (nmKnobSizeH)))
    {
        color = over(knobColor, color);
        color = over(knobLayer1, color);
    }

    //knob2 color
    if (level > (remapValue2 - (nmKnobSizeH)) &&
  								level < (remapValue2 + (nmKnobSizeH)))
    {
        color = over(knobColor, color);
        color = over(knobLayer2, color);
    }

	//Text over
    //color = over(textLayer, color);
	fragColor = color;
}

