TDF = op.TDModules.mod.TDFunctions

class NumericFieldExt(SubWidgetExt):
	"""
	NumericFieldExt description
	"""
	def __init__(self, ownerComp):
		# The component to which this extension is attached
		self.parPrefix = 'Numericfield'
		SubWidgetExt.__init__(self, ownerComp)

	def onParSettingsChange(self, par, prev):
		"""
		Manages value changes widget settings parameters
		"""
		val = par.eval()
		if par.name == 'Numericfieldtype':
			if val == 'integer':
				parent.Widget.par.Numericfielddecimalplaces.enable = False
			else:
				parent.Widget.par.Numericfielddecimalplaces.enable = True
		else:
			SubWidgetExt.onParSettingsChange(self, par, prev)

	def makePanelExecute(self):
		SubWidgetExt.makePanelExecute(self,
					self.getDockExpressionToOwner() + '.op("field")')

